  vocab: [{ hi: "चाय", fr: "thé", ipa: "chai" }, { hi: "कॉफ़ी", fr: "café", ipa: "kofi" }, { hi: "दूध", fr: "lait", ipa: "doodh" }, { hi: "चीनी", fr: "sucre", ipa: "cheeni" }, { hi: "बिना", fr: "sans", ipa: "bina" }, { hi: "साथ", fr: "avec", ipa: "saath" }, { hi: "कप", fr: "tasse", ipa: "kap" }, { hi: "गिलास", fr: "verre", ipa: "gilaas" }, { hi: "नाश्ता", fr: "petit-déjeuner / snack", ipa: "naashta" }, { hi: "ले जाना", fr: "emporter", ipa: "lé jaana" }],
  phrases: [{ hi: "एक चाय दीजिए।", fr: "Donnez-moi un thé.", ipa: "ek chai dijié" }, { hi: "बिना चीनी, कृपया।", fr: "Sans sucre, s’il vous plaît.", ipa: "bina cheeni, kripaya" }, { hi: "दूध के साथ।", fr: "Avec du lait.", ipa: "doodh ké saath" }, { hi: "मुझे कॉफ़ी चाहिए।", fr: "Je voudrais un café.", ipa: "mujhé kofi chahié" }, { hi: "यहाँ पीना है।", fr: "C’est pour boire ici.", ipa: "yahaan peena hai" }, { hi: "ले जाना है।", fr: "C’est à emporter.", ipa: "lé jaana hai" }],
  grammar: "“दीजिए” est une forme polie de “donnez”. Elle est très fréquente pour commander dans un café, une boutique ou une billetterie. “बिना” signifie “sans”, tandis que “के साथ” signifie “avec”. Pour dire “à emporter”, “ले जाना है” est simple et compris dans beaucoup de contextes.",
  practice: ["Commandez un thé.", "Demandez un café sans sucre.", "Dites que vous voulez boire sur place.", "Dites que vous voulez emporter.", "Ajoutez “कृपया” à deux commandes."]
