  title: "Acheter au marché",
  titleNative: "बाज़ार में ख़रीदारी",
  focus: "Dans les marchés de Jaipur, Delhi ou Udaipur, vous devez demander les prix et choisir des objets. Aujourd’hui, vous apprenez les bases de l’achat.",
  vocab: [{ hi: "बाज़ार", fr: "marché", ipa: "baazaar" }, { hi: "दाम", fr: "prix", ipa: "daam" }, { hi: "सस्ता", fr: "bon marché", ipa: "sasta" }, { hi: "महँगा", fr: "cher", ipa: "mahanga" }, { hi: "कपड़ा", fr: "tissu / vêtement", ipa: "kapda" }, { hi: "जूते", fr: "chaussures", ipa: "jooté" }, { hi: "यादगार", fr: "souvenir", ipa: "yaadgaar" }, { hi: "रंग", fr: "couleur", ipa: "rang" }, { hi: "छोटा", fr: "petit", ipa: "chhota" }, { hi: "बड़ा", fr: "grand", ipa: "bada" }],
  phrases: [{ hi: "यह कितना है?", fr: "Combien ça coûte ?", ipa: "yé kitna hai?" }, { hi: "बहुत महँगा है।", fr: "C’est très cher.", ipa: "bahut mahanga hai" }, { hi: "कुछ सस्ता है?", fr: "Avez-vous quelque chose de moins cher ?", ipa: "kuchh sasta hai?" }, { hi: "मुझे यह रंग पसंद है।", fr: "J’aime cette couleur.", ipa: "mujhé yé rang pasand hai" }, { hi: "छोटा साइज़ है?", fr: "Avez-vous une petite taille ?", ipa: "chhota size hai?" }, { hi: "मैं यह लूँगा।", fr: "Je vais prendre ceci.", ipa: "main yé loonga" }],
  grammar: "“पसंद है” signifie “aimer / plaire”. La structure est différente du français: “मुझे यह पसंद है” signifie littéralement “ceci me plaît”. Pour dire “je vais prendre”, un homme peut dire “मैं यह लूँगा” et une femme “मैं यह लूँगी”. Dans les marchés, le ton poli aide beaucoup même lorsque vous négociez.",
  practice: ["Demandez le prix d’un souvenir.", "Dites que c’est trop cher.", "Demandez une option moins chère.", "Dites que vous aimez une couleur.", "Choisissez un objet et dites que vous le prenez."]
