  phrases: [{ hi: "मदद कीजिए!", fr: "Aidez-moi !", ipa: "madad kijié" }, { hi: "पुलिस को बुलाइए।", fr: "Appelez la police.", ipa: "polis ko bulaiyé" }, { hi: "मेरा फ़ोन गुम हो गया है।", fr: "Mon téléphone est perdu.", ipa: "méra fon gum ho gaya hai" }, { hi: "मेरा पासपोर्ट चोरी हो गया है।", fr: "Mon passeport a été volé.", ipa: "méra passport chori ho gaya hai" }, { hi: "अस्पताल कहाँ है?", fr: "Où est l’hôpital ?", ipa: "aspataal kahaan hai?" }, { hi: "यह आपात स्थिति है।", fr: "C’est une urgence.", ipa: "yé aapaat sthiti hai" }],
  grammar: "“हो गया है” indique qu’un changement ou événement s’est produit. “गुम हो गया है” signifie “est devenu perdu”, donc “a été perdu”. Pour les objets féminins, on peut entendre “हो गई है”. Dans une urgence, la clarté est plus importante que la grammaire parfaite.",
  practice: ["Criez “aidez-moi”.", "Demandez à quelqu’un d’appeler la police.", "Dites que votre téléphone est perdu.", "Dites que votre passeport a été volé.", "Demandez où est l’hôpital."]
