  phrases: [{ hi: "मुझे संगीत पसंद है।", fr: "J’aime la musique.", ipa: "mujhé sangeet pasand hai" }, { hi: "मुझे यह खाना पसंद है।", fr: "J’aime cette nourriture.", ipa: "mujhé yé khaana pasand hai" }, { hi: "मुझे तीखा खाना पसंद नहीं है।", fr: "Je n’aime pas la nourriture piquante.", ipa: "mujhé teekha khaana pasand nahin hai" }, { hi: "आपको क्या पसंद है?", fr: "Qu’est-ce que vous aimez ?", ipa: "aapko kya pasand hai?" }, { hi: "मुझे घूमना पसंद है।", fr: "J’aime voyager / me promener.", ipa: "mujhé ghoomna pasand hai" }, { hi: "मुझे भारतीय फ़िल्में पसंद हैं।", fr: "J’aime les films indiens.", ipa: "mujhé bhaaratiya filmen pasand hain" }],
