  phrases: [{ hi: "क्या आप कॉफ़ी पीना चाहेंगे?", fr: "Voulez-vous boire un café ?", ipa: "kya aap kofi peena chaahengé?" }, { hi: "हम साथ चलें?", fr: "On y va ensemble ?", ipa: "ham saath chalén?" }, { hi: "आपसे मिलकर खुशी हुई।", fr: "Ravi de vous rencontrer.", ipa: "aapsé milkar khushi hui" }, { hi: "मेरे पास समय है।", fr: "J’ai du temps.", ipa: "méré paas samay hai" }, { hi: "ज़रूर, अच्छा रहेगा।", fr: "Bien sûr, ce sera bien.", ipa: "zaroor, acchaa rahéga" }, { hi: "माफ़ कीजिए, आज नहीं।", fr: "Désolé, pas aujourd’hui.", ipa: "maaf kijié, aaj nahin" }],
