  phrases: [{ hi: "आज बहुत गर्मी है।", fr: "Il fait très chaud aujourd’hui.", ipa: "aaj bahut garmi hai" }, { hi: "मौसम अच्छा है।", fr: "Le temps est agréable.", ipa: "mausam acchaa hai" }, { hi: "बारिश हो रही है।", fr: "Il pleut.", ipa: "baarish ho rahi hai" }, { hi: "मुझे थोड़ा आराम चाहिए।", fr: "J’ai besoin d’un peu de repos.", ipa: "mujhé thoda aaraam chahié" }, { hi: "मैं थक गया हूँ।", fr: "Je suis fatigué.", ipa: "main thak gaya hoon" }, { hi: "ठंडा पानी चाहिए।", fr: "Je voudrais de l’eau froide.", ipa: "thanda paani chahié" }],
